changeSet.sql:
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = '${app_role_name}') THEN
        EXECUTE format('CREATE ROLE %I LOGIN PASSWORD %L', '${app_role_name}', '${app_role_password}');
    END IF;
END
$$;

GRANT USAGE ON SCHEMA public TO ${app_role_name};

-- Default deny, then grant the minimum each table class needs.
REVOKE ALL ON ALL TABLES IN SCHEMA public FROM ${app_role_name};

-- Regulated MUTABLE tables: SELECT, INSERT, UPDATE (NO DELETE -> soft delete only).
GRANT SELECT, INSERT, UPDATE ON
    sites, departments, roles, permissions, users, user_roles,
    role_permissions, attachments, record_sequences
TO ${app_role_name};

-- Append-only audit trail: SELECT + INSERT only.
GRANT SELECT, INSERT ON audit_logs TO ${app_role_name};

-- Immutable signatures: SELECT + INSERT only.
GRANT SELECT, INSERT ON electronic_signatures TO ${app_role_name};

-- Identity-column / sequence usage.
GRANT USAGE, SELECT ON ALL SEQUENCES IN SCHEMA public TO ${app_role_name};
